import { Link, useLocation } from 'react-router-dom';
import '../styles/navbar.css';
import { useState, useEffect } from 'react';

function Navbar() {
  const [menuOpen, setMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
    };
    window.addEventListener("scroll", handleScroll);
  }, []);

  return (
    <>
      {/* TOP INFO BAR */}
      <div className="topbar">
        <div className="top-left">
          <span>📍 Chuka, Ndagani</span>
          <span>✉ info@jpmtchospital.org</span>
        </div>

        <div className="top-right">
          <span className="hotline">Hotline - 1234567</span>
        </div>
      </div>

      {/* MAIN NAVBAR */}
      <nav className={scrolled ? "navbar scrolled" : "navbar"}>

        {/* LOGO */}
        <div className="logo">
          <img 
            src="/purveyors_images/logo.png" 
            alt="logo"
          />
          {/* Replace above with your image inside /public/purveyors_images */}
          
          <div>
            <h2>JOY PURVEYORS</h2>
            <span>Medical Centre</span>
          </div>
        </div>

        {/* MENU TOGGLE */}
        <div className="menu-toggle" onClick={() => setMenuOpen(!menuOpen)}>
          ☰
        </div>

        {/* NAV LINKS */}
        <ul className={menuOpen ? "nav-links active" : "nav-links"}>

          <li>
            <Link className={location.pathname === "/" ? "active" : ""} to="/">Home</Link>
          </li>

          <li>
            <Link className={location.pathname === "/about" ? "active" : ""} to="/about">About</Link>
          </li>

          <li>
            <Link to="/services">Services</Link>
          </li>

          <li>
            <Link className={location.pathname === "/contact" ? "active" : ""} to="/contact">Contact</Link>
          </li>

          <li>
            <Link to="/appointment" className="btn-book">Book Appointment</Link>
          </li>

        </ul>

      </nav>
    </>
  );
}

export default Navbar;
